SELECT
FROM picture WHERE isDelete = 0 AND isDraft = 0 AND reviewStatus = 1 AND spaceId = #{spaceId}
AND (createTime < #{cursorCreateTime} OR (createTime = #{cursorCreateTime} AND id < #{cursorId}))
ORDER BY createTime DESC, id DESC LIMIT #{pageSize}

SELECT
FROM picture WHERE isDelete = 0 AND userId = #{userId}
AND (createTime < #{cursorCreateTime} OR (createTime = #{cursorCreateTime} AND id < #{cursorId}))
ORDER BY createTime DESC, id DESC LIMIT #{pageSize}

SELECT

FROM picture
WHERE isDelete = 0
AND isDraft = 0
AND reviewStatus = 1

    AND spaceId = #{spaceId}


    AND userId = #{userId}


    AND category = #{category}


    AND tags LIKE CONCAT('%', #{tags}, '%')


    AND (
    name LIKE CONCAT('%', #{searchText}, '%')
    OR introduction LIKE CONCAT('%', #{searchText}, '%')
    )

ORDER BY createTime DESC, id DESC
LIMIT #{pageSize} OFFSET #{offset}
